        fw_s08_li2: 'Operational rules designed to eliminate decision fatigue',
        fw_s08_li3: 'A repeatable execution model applicable across multiple cycles',
        fw_s08_li4: 'A professional evaluation standard for behavioral consistency measurement',
        fw_s08_li5: 'Structured journaling and self-review protocols',
