        prep_s5_num: 'Section 05',
        prep_s5_title: "What's Included After Purchase",
        prep_s5_p1: 'Upon completing your PREPARE purchase, you gain immediate access to the following components:',
        prep_s5_inc1_title: 'Qualification System',
        prep_s5_inc1_desc: 'Full access to the interactive PREPARE qualification interface with real-time compliance tracking and trade submission.',
        prep_s5_inc2_title: 'Session Execution Window',
        prep_s5_inc2_desc: 'Designated trading session parameters with defined execution boundaries for structured qualification.',
        prep_s5_inc3_title: 'Risk Allocation Framework',
