        prep_s5_inc5_title: 'Behavioral Compliance Scoring',
        prep_s5_inc5_desc: 'Trader OS integration with per-trade scoring, violation tracking, and behavioral analysis metrics.',
        prep_s5_inc6_title: 'Challenge Unlock',
        prep_s5_inc6_desc: 'Successful PREPARE qualification unlocks access to purchase Framework Pack and US100 Challenge products.',
        prep_s5_note: 'All components are delivered immediately upon purchase. PREPARE is a one-time qualification — no recurring fees.',
        price_acc_btn: 'Subscribe — Accessories',
        price_acc_desc: 'Standalone monthly access to the full Accessories suite. No PREPARE required. Subscribe independently.',
        price_acc_fine: 'Monthly subscription. No PREPARE required.',
        price_acc_label: 'Accessories Subscription',
