function getTranslationValue(lang, key, fallback = '') {
    const current = TRANSLATIONS[lang] || {};
    if (current[key] !== undefined) return current[key];
    const english = TRANSLATIONS.en || {};
    if (english[key] !== undefined) return english[key];
    return fallback;
}

function formatTranslation(value, replacements) {
    if (!replacements) return value;
    return String(value).replace(/\{(\w+)\}/g, function (_, token) {
        return replacements[token] !== undefined ? replacements[token] : `{${token}}`;
    });
}

window.altivorGetTranslation = function (key, fallback = '', replacements) {
    const lang = document.documentElement.getAttribute('lang') || 'en';
    return formatTranslation(getTranslationValue(lang, key, fallback), replacements);
};

function applyStaticTranslations(lang) {
    STATIC_TEXT_BINDINGS.forEach(function (binding) {
        const value = getTranslationValue(lang, binding.key);
        if (value === undefined) return;
        document.querySelectorAll(binding.selector).forEach(function (el) {
            el.textContent = value;
        });
    });

    STATIC_HTML_BINDINGS.forEach(function (binding) {
        const value = getTranslationValue(lang, binding.key);
        if (value === undefined) return;
        document.querySelectorAll(binding.selector).forEach(function (el) {
            el.innerHTML = value;
        });
    });

    STATIC_ATTR_BINDINGS.forEach(function (binding) {
        const value = getTranslationValue(lang, binding.key);
        if (value === undefined) return;
        document.querySelectorAll(binding.selector).forEach(function (el) {
            el.setAttribute(binding.attr, value);
        });
    });
}

function applyLanguage(lang) {
    const t = TRANSLATIONS[lang];
    if (!t) return;
    const en = TRANSLATIONS.en || {};
    const meta = LANG_META[lang];

    const _missingLogged = new Set();
    function resolve(key) {
        if (t[key] !== undefined) return t[key];
        if (en[key] !== undefined) return en[key];
        if (!_missingLogged.has(key)) { _missingLogged.add(key); console.warn('[i18n] missing key:', key, '(lang=' + lang + ')'); }
        return undefined;
    }

    // Direction + lang attr
    document.documentElement.setAttribute('lang', lang);
    document.documentElement.setAttribute('dir', meta.dir);

    // Update all data-i18n elements
    document.querySelectorAll('[data-i18n]').forEach(el => {
        const key = el.getAttribute('data-i18n');
        const val = resolve(key);
        if (val !== undefined) {
            if (el.tagName === 'INPUT' || el.tagName === 'TEXTAREA') {
                el.placeholder = val;
            } else {
                el.innerHTML = val;
            }
        }
    });

    document.querySelectorAll('[data-i18n-placeholder]').forEach(el => {
        const key = el.getAttribute('data-i18n-placeholder');
        const val = resolve(key);
        if (val !== undefined) {
            el.setAttribute('placeholder', val);
        }
    });

    document.querySelectorAll('[data-i18n-title]').forEach(el => {
        const key = el.getAttribute('data-i18n-title');
        const val = resolve(key);
        if (val !== undefined) {
            el.setAttribute('title', val);
        }
    });

    document.querySelectorAll('[data-i18n-aria-label]').forEach(el => {
        const key = el.getAttribute('data-i18n-aria-label');
        const val = resolve(key);
        if (val !== undefined) {
            el.setAttribute('aria-label', val);
        }
    });

    document.querySelectorAll('[data-i18n-content]').forEach(el => {
        const key = el.getAttribute('data-i18n-content');
        const val = resolve(key);
        if (val !== undefined) {
            el.setAttribute('content', val);
        }
    });

    document.querySelectorAll('[data-i18n-value]').forEach(el => {
        const key = el.getAttribute('data-i18n-value');
        const val = resolve(key);
        if (val !== undefined) {
            el.setAttribute('value', val);
        }
    });

    applyStaticTranslations(lang);

    // Update language picker button label
    const btn = document.getElementById('langPickerBtn');
    if (btn) btn.innerHTML = `<span class="lang-flag-circle"><img src="${meta.flag}" alt="${meta.label}" class="lang-flag-img"></span><span class="lang-code">${meta.label}</span><svg class="lang-chevron" viewBox="0 0 10 6" fill="none"><path d="M1 1l4 4 4-4" stroke="currentColor" stroke-width="1.5" stroke-linecap="round"/></svg>`;

    localStorage.setItem(LANG_KEY, lang);

    // RTL adjustments
    document.body.classList.toggle('rtl', meta.dir === 'rtl');

    // Auto-fit nav: shrink text if nav-links overflows
    requestAnimationFrame(fitNav);

    document.dispatchEvent(new CustomEvent('altivor:languagechange', {
        detail: { lang }
    }));
}

function fitNav() {
    const inner = document.querySelector('.nav-inner');
    const links = document.querySelector('.nav-links');
    if (!inner || !links) return;

    const actionWrap = inner.querySelector('.nav-actions');
    const navLinks = links.querySelectorAll('a, .nav-dropdown-trigger');
    const navCtas = inner.querySelectorAll('.nav-actions .nav-cta');
    const themeButtons = inner.querySelectorAll('.theme-btn');

    inner.classList.remove('nav-inner--compressed');

    // Reset to base sizes first
    links.style.removeProperty('font-size');
    links.style.removeProperty('gap');
    navLinks.forEach(el => {
        el.style.removeProperty('font-size');
        el.style.removeProperty('letter-spacing');
    });

    if (actionWrap) {
        actionWrap.style.removeProperty('gap');
    }

    navCtas.forEach(el => {
        el.style.removeProperty('font-size');
        el.style.removeProperty('padding');
    });

    themeButtons.forEach(el => {
        el.style.removeProperty('font-size');
        el.style.removeProperty('padding');
    });

    if (window.innerWidth < 1100) return;

    // Only shrink if nav actually overflows at default CSS size
    if (inner.scrollWidth <= inner.clientWidth + 2) return;

    const steps = [
        { linkSize: 0.875, linkGap: 2, linkLetterSpacing: '0.01em', ctaSize: 0.82, ctaPadding: '0.48rem 1rem', themeSize: 0.76, themePadding: '0.3rem 0.68rem', actionGap: '0.5rem', compact: false },
        { linkSize: 0.82, linkGap: 1.5, linkLetterSpacing: '0.01em', ctaSize: 0.78, ctaPadding: '0.44rem 0.9rem', themeSize: 0.72, themePadding: '0.26rem 0.58rem', actionGap: '0.42rem', compact: false },
        { linkSize: 0.78, linkGap: 1.1, linkLetterSpacing: '0.01em', ctaSize: 0.74, ctaPadding: '0.4rem 0.8rem', themeSize: 0.68, themePadding: '0.24rem 0.5rem', actionGap: '0.36rem', compact: false },
        { linkSize: 0.74, linkGap: 0.8, linkLetterSpacing: '0.005em', ctaSize: 0.7, ctaPadding: '0.36rem 0.7rem', themeSize: 0.64, themePadding: '0.22rem 0.42rem', actionGap: '0.3rem', compact: false },
        { linkSize: 0.7, linkGap: 0.55, linkLetterSpacing: '0.005em', ctaSize: 0.66, ctaPadding: '0.32rem 0.6rem', themeSize: 0.6, themePadding: '0.2rem 0.36rem', actionGap: '0.24rem', compact: true }
    ];

    for (let i = 0; i < steps.length; i++) {
        const step = steps[i];
        inner.classList.toggle('nav-inner--compressed', step.compact);
        links.style.gap = step.linkGap + 'rem';
        navLinks.forEach(el => {
            el.style.fontSize = step.linkSize + 'rem';
            el.style.letterSpacing = step.linkLetterSpacing;
        });
        navCtas.forEach(el => {
            el.style.fontSize = step.ctaSize + 'rem';
            el.style.padding = step.ctaPadding;
        });
        themeButtons.forEach(el => {
            el.style.fontSize = step.themeSize + 'rem';
            el.style.padding = step.themePadding;
        });
        if (actionWrap) {
            actionWrap.style.gap = step.actionGap;
        }

        if (inner.scrollWidth <= inner.clientWidth + 2) break;
    }
}

window.addEventListener('resize', fitNav, { passive: true });

function initLangPicker() {
    const picker = document.getElementById('langPicker');
    const btn = document.getElementById('langPickerBtn');
    const dropdown = document.getElementById('langDropdown');
    if (!picker || !btn || !dropdown) return;

    // Build FTMO-style dropdown items
    dropdown.innerHTML = Object.entries(LANG_META).map(([code, m]) =>
        `<button class="lang-option" data-lang="${code}" type="button">
      <span class="lang-flag-circle lang-option-flag"><img src="${m.flag}" alt="${m.label}" class="lang-flag-img"></span>
      <span class="lang-option-name">${m.name}</span>
      <span class="lang-option-code">${m.label}</span>
    </button>`
    ).join('');

    btn.addEventListener('click', (e) => {
        e.stopPropagation();
        picker.classList.toggle('open');
    });

    dropdown.querySelectorAll('.lang-option').forEach(opt => {
        opt.addEventListener('click', () => {
            applyLanguage(opt.dataset.lang);
            picker.classList.remove('open');
            dropdown.querySelectorAll('.lang-option').forEach(o => o.classList.remove('active'));
            opt.classList.add('active');
            updateActiveLang(opt.dataset.lang);
        });
    });

    document.addEventListener('click', () => picker.classList.remove('open'));

    function updateActiveLang(lang) {
        dropdown.querySelectorAll('.lang-option').forEach(o => {
            o.classList.toggle('active', o.dataset.lang === lang);
        });
    }

    // Always start with English regardless of saved preference or IP
    const initLang = 'en';
    applyLanguage(initLang);
    updateActiveLang(initLang);
}

document.addEventListener('DOMContentLoaded', initLangPicker);

